// This CSD strategy generates valid mathematical expressions for GSM-Symbolic reasoning.
// It ensures the expression starts with a variable, uses balanced parentheses,
// and respects the grammar's constraints such as recursive depth and the presence of '>>' delimiter.
// The strategy uses constrained steps to explore possible expressions and rollback to valid prefixes.
// It maintains the invariant that the generated expression is valid and complete.
// CSD_RATIONALE_END

generated := [];
var stepsLeft := maxSteps;

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  // Ensure the generated expression is valid
  CSDHelpers.RollbackPreservesTokenInvariant(lm, parser, generated);

  // Determine whether to use a constrained or unconstrained step
  var canConstrain := !parser.IsCompletePrefix(generated);

  // Choose the appropriate step based on the parser and contract
  var (next, newSteps) := canConstrain ?
    helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft) :
    helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);

  // Append the next token to the generated expression
  generated := generated + [next];

  // Update the remaining steps
  stepsLeft := newSteps;
}

remainingSteps := stepsLeft;
